class Solution:
    def splitPainting(self, segments):
        # Independent: enumerate every elementary interval and sum covering colors directly.
        coords = sorted({x for s, e, c in segments for x in (s, e)})
        res = []
        for i in range(len(coords) - 1):
            a, b = coords[i], coords[i + 1]
            total = 0
            for s, e, c in segments:
                if s <= a and b <= e:
                    total += c
            if total > 0:
                res.append([a, b, total])
        return res

